import { Component, OnInit } from '@angular/core';
import { User } from '../../core/models/user.model';
import { WorkRecord } from '../../core/models/record.model';
import { AuthService } from '../../core/services/auth.service';
import { RecordService } from '../../core/services/record.service';

@Component({
  selector: 'app-workspace',
  templateUrl: './workspace.component.html'
})
export class WorkspaceComponent implements OnInit {
  user: User | null = null;
  records: WorkRecord[] = [];
  accessNote = '';
  delay = 1600;
  loading = false;
  error = '';

  constructor(private readonly auth: AuthService, private readonly recordsApi: RecordService) {}

  ngOnInit(): void {
    this.user = this.auth.currentUser;
    this.loadRecords();
  }

  loadRecords(): void {
    this.loading = true;
    this.error = '';

    this.recordsApi.list(this.delay).subscribe({
      next: (response) => {
        this.records = response.records;
        this.accessNote = response.accessNote;
      },
      error: (error) => {
        this.error = error.error?.message || 'Unable to load records';
        this.loading = false;
      },
      complete: () => (this.loading = false)
    });
  }
}
<section class="workspace">
  <div class="page-title">
    <div>
      <p class="eyebrow">Logged in page</p>
      <h1>Welcome, {{ user?.name }}</h1>
    </div>
    <div class="delay-control">
      <label for="delay">API delay</label>
      <input id="delay" type="range" min="0" max="5000" step="200" [(ngModel)]="delay">
      <strong>{{ delay }}ms</strong>
      <button type="button" (click)="loadRecords()">Reload</button>
    </div>
  </div>

  <div class="profile-grid">
    <article>
      <span>User ID</span>
      <strong>{{ user?.userId }}</strong>
    </article>
    <article>
      <span>Role</span>
      <strong>{{ user?.role }}</strong>
    </article>
    <article>
      <span>Department</span>
      <strong>{{ user?.department }}</strong>
    </article>
    <article>
      <span>Async State</span>
      <strong>{{ loading ? 'Waiting for delayed API' : 'Ready' }}</strong>
    </article>
  </div>

  <section class="table-section">
    <div class="table-heading">
      <div>
        <h2>Accessible Records</h2>
        <p>{{ accessNote }}</p>
      </div>
      <span class="pill">{{ records.length }} records</span>
    </div>

    <div class="loading-bar" *ngIf="loading"></div>
    <p class="error" *ngIf="error">{{ error }}</p>

    <table>
      <thead>
        <tr>
          <th>Customer</th>
          <th>Opportunity</th>
          <th>Value</th>
          <th>Status</th>
          <th>Access</th>
          <th>Updated</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let record of records">
          <td>{{ record.customer }}</td>
          <td>{{ record.opportunity }}</td>
          <td>{{ record.value | currency:'INR':'symbol':'1.0-0' }}</td>
          <td><span class="status">{{ record.status }}</span></td>
          <td>{{ record.accessLevel }}</td>
          <td>{{ record.updatedAt | date:'mediumDate' }}</td>
        </tr>
      </tbody>
    </table>
  </section>
</section>
